     1→// ── Agent State Machine ──────────────────────────────────────────────
     2→//
     3→// Defines explicit state transitions, per-state actions with keybindings,
     4→// and runtime filtering for context-dependent action availability.
     5→
     6→// ── Types ────────────────────────────────────────────────────────────
     7→
     8→export type AgentState =
     9→  | "setup"
    10→  | "running"
    11→  | "teardown"
    12→  | "completed"
    13→  | "failed"
    14→  | "cancelled"
    15→  | "interrupted";
    16→
    17→export type AgentEvent =
    18→  | "SETUP_COMPLETE"
    19→  | "TEARDOWN_START"
    20→  | "TEARDOWN_COMPLETE"
    21→  | "ERROR"
    22→  | "USER_KILL"
    23→  | "SESSION_CLOSE";
    24→
    25→export type AgentAction =
    26→  | "attach"
    27→  | "open_pr"
    28→  | "shell"
    29→  | "continue_pr"
    30→  | "kill"
    31→  | "delete"
    32→  | "toggle_logs"
    33→  | "retry";
    34→
    35→export interface AgentContext {
    36→  status: AgentState;
    37→  hasPrUrl: boolean;
    38→  hasFinalBranch: boolean;
    39→  hasMeta: boolean;
    40→  prState: "open" | "merged" | "closed" | null;
    41→}
    42→
    43→interface ActionBinding {
    44→  keyDisplay: string;
    45→  label: string;
    46→}
    47→
    48→// ── Transition Table ─────────────────────────────────────────────────
    49→
    50→const TRANSITIONS: Record<AgentState, Partial<Record<AgentEvent, AgentState>>> = {
    51→  setup:       { SETUP_COMPLETE: "running", ERROR: "failed", USER_KILL: "cancelled" },
    52→  running:     { TEARDOWN_START: "teardown", ERROR: "failed", USER_KILL: "cancelled", SESSION_CLOSE: "interrupted" },
    53→  teardown:    { TEARDOWN_COMPLETE: "completed", ERROR: "failed" },
    54→  completed:   {},
    55→  failed:      {},
    56→  cancelled:   {},
    57→  interrupted: { SETUP_COMPLETE: "running" },
    58→};
    59→
    60→/**
    61→ * Attempt a state transition. Returns the next state, or null if the
    62→ * transition is invalid for the current state.
    63→ */
    64→export function transition(current: AgentState, event: AgentEvent): AgentState | null {
    65→  return TRANSITIONS[current][event] ?? null;
    66→}
    67→
    68→// ── Action Map per State ─────────────────────────────────────────────
    69→
    70→const ACTIONS_BY_STATE: Record<AgentState, AgentAction[]> = {
    71→  setup:       ["kill", "toggle_logs"],
    72→  running:     ["attach", "shell", "kill", "toggle_logs"],
    73→  teardown:    ["toggle_logs"],
    74→  completed:   ["open_pr", "shell", "continue_pr", "delete", "toggle_logs"],
    75→  failed:      ["retry", "shell", "delete", "toggle_logs"],
    76→  cancelled:   ["shell", "delete", "toggle_logs"],
    77→  interrupted: ["delete", "toggle_logs"],
    78→};
    79→
    80→// ── Action Bindings ──────────────────────────────────────────────────
    81→
    82→export const ACTION_BINDINGS: Record<AgentAction, ActionBinding> = {
    83→  attach:       { keyDisplay: "⏎", label: "attach" },
    84→  open_pr:      { keyDisplay: "⏎", label: "open PR" },
    85→  shell:        { keyDisplay: "s", label: "shell" },
    86→  continue_pr:  { keyDisplay: "c", label: "continue PR" },
    87→  kill:         { keyDisplay: "x", label: "kill" },
    88→  delete:       { keyDisplay: "⌫", label: "delete" },
    89→  toggle_logs:  { keyDisplay: "l", label: "logs" },
    90→  retry:        { keyDisplay: "r", label: "retry" },
    91→};
    92→
    93→// ── Runtime Filtering ────────────────────────────────────────────────
    94→
    95→/**
    96→ * Returns the actions available for an agent given its current context.
    97→ * Filters the base action list by secondary conditions (e.g. open_pr
    98→ * requires a PR URL, delete is blocked when PR is open).
    99→ */
   100→export function availableActions(ctx: AgentContext): AgentAction[] {
   101→  const base = ACTIONS_BY_STATE[ctx.status];
   102→  return base.filter((action) => {
   103→    switch (action) {
   104→      case "open_pr":
   105→        return ctx.hasPrUrl;
   106→      case "shell":
   107→        return ctx.hasMeta;
   108→      case "continue_pr":
   109→        return ctx.hasFinalBranch;
   110→      case "delete":
   111→        return ctx.prState !== "open";
   112→      default:
   113→        return true;
   114→    }
   115→  });
   116→}
   117→
   118→// ── Key Resolution ───────────────────────────────────────────────────
   119→
   120→interface KeyInfo {
   121→  return?: boolean;
   122→  backspace?: boolean;
   123→  delete?: boolean;
   124→  [key: string]: unknown;
   125→}
   126→
   127→/**
   128→ * Maps a raw keypress to an action, but only if that action is in the
   129→ * available set. Returns null if no match or action is unavailable.
   130→ */
   131→export function resolveKeypress(
   132→  input: string,
   133→  key: KeyInfo,
   134→  actions: AgentAction[],
   135→): AgentAction | null {
   136→  // Enter key: attach takes priority over open_pr
   137→  if (key.return) {
   138→    if (actions.includes("attach")) return "attach";
   139→    if (actions.includes("open_pr")) return "open_pr";
   140→    return null;
   141→  }
   142→
   143→  // Backspace / Delete key
   144→  if (key.backspace || key.delete) {
   145→    return actions.includes("delete") ? "delete" : null;
   146→  }
   147→
   148→  // Character keys
   149→  const charMap: Record<string, AgentAction> = {
   150→    x: "kill",
   151→    s: "shell",
   152→    c: "continue_pr",
   153→    l: "toggle_logs",
   154→    r: "retry",
   155→  };
   156→
   157→  const action = charMap[input];
   158→  if (action && actions.includes(action)) return action;
   159→
   160→  return null;
   161→}
   162→

