   862→// ── Main Component ───────────────────────────────────────────────────
   863→
   864→export default function Dashboard({ cwd }: { cwd: string }) {
   865→  const { exit } = useApp();
   866→  const { stdout } = useStdout();
   867→  const termWidth = stdout?.columns || 80;
   868→  const termHeight = stdout?.rows || 24;
   869→
   870→  const [agents, setAgents] = useState<AgentState[]>([]);
